var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세계는 마치 신이 인류의 자격을 시험하듯 끊임없이 재난을 만들어내지.","JPN":"世界はまるで神が人類の資格を試すかのように、絶えず災害を生み出す。","ENG":"The world keeps birthing disasters, almost like a test from the gods to see if humanity deserves to survive.","TWN":"世界彷彿在考驗人類的資格，不斷地製造災難。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 때론, 인류에게 시련을 주기 위해 태어난 재난들이 서로를 잡아먹기도 한다네.","JPN":"時には人類に試練を与えるために生まれた災害同士が、互いを食らいつくすこともある。","ENG":"And sometimes, those disasters meant to test us start devouring each other.","TWN":"有時，為了給人類帶來考驗而誕生的災難，也會互相吞噬。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 자기들끼리 먹고 먹혀 소멸했다면 좋았겠지만… 그것들은 불사의 몸을 가진 탓에 서로를 먹어치우며 끊임없이 커져버리고 말았어.","JPN":"そうやって互いに食らい合って消滅したら良かったのだが……それらは不死の体を持つがために、食らうことで際限なく大きくなってしまった。","ENG":"If only they had eaten each other into extinction… But they couldn't. Their bodies are immortal, so they just kept growing.","TWN":"如果牠們能這樣互相吞噬而消亡就好了… 但牠們擁有不死之身，互相吞噬後反而會不斷壯大。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 재난이란 게… 바로 관리국이 말하는 세 짐승인가?","JPN":"その災害とは……管理局でいう3匹のケモノのことか？","ENG":"Are you saying these disasters… are what the Administration calls the Three Beasts?","TWN":"你說的災難… 就是管理局所說的三隻野獸嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Exactly.","TWN":"沒錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세 짐승의 머리가 커질대로 커져 지성이 생겼을 때쯤엔 자신들의 끊임없는 결핍을 달래줄 유일한 수단이 인간이란 걸 알게 됐지.","JPN":"3匹のケモノがだんだん成長し、知性を持ち始めた頃……やつらは自分たちの果てしない飢えを満たせる唯一の存在が、人間だということを知った。","ENG":"When the Three Beasts' grew enough power to gain an intelligence of their own, they figured out that the only thing that could satisfy their bottomless hunger was humanity.","TWN":"當三隻野獸的頭顱越來越大，產生了智慧後，牠們意識到唯一能填補牠們無盡空缺的方法，就是人類。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"짐승들은 인간을 잡아먹기 시작했고, 그 결핍을 채우면 채울수록 놈들은 단순한 재난이 아닌 완성된 존재로 거듭나기 시작했다네.","JPN":"ケモノたちは人間を食らうようになり、飢えを満たせば満たせるほど、やつらは単なる災害ではなく完成した存在へと変貌を遂げ始めた。","ENG":"The Beasts started consuming humans. And the more they fed, the less they remained disasters and the more they became something complete.","TWN":"野獸開始吞噬人類，而牠們越是填補空缺，就越是從單純的災難，蛻變為完整的存在。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"짐승들이 완성된 존재가 된다는 건… 어떤 의미요?","JPN":"ケモノが完成した存在になるとは、どういう意味だ？","ENG":"Complete…? What do you mean?","TWN":"野獸成為完整的存在… 是什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세계와 운명이란 고리로 엮여 하나가 되는 것.","JPN":"運命という輪で世界と繋がり一つになること。","ENG":"Becoming one with the world by intertwining with fate itself.","TWN":"與世界和命運連結為一。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우린 그런 존재를 마왕이라 정의한다네.","JPN":"我々はそのような存在を「魔王」と定義している。","ENG":"We call that kind of being… a Demon Lord.","TWN":"我們將這種存在，定義為魔王。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그러고보니 동월은… 15일도 남지 않았다는 말을 했었소.","JPN":"そういえば先程トウゲツは……あと15日もないと言っていた。","ENG":"Come to think of it, Dongwol said… that we don't even have fifteen days left.","TWN":"話說佟月… 說只剩下15天了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇담 그 15일이란 건…?","JPN":"ということは、その15日とは……？","ENG":"Then that fifteen days mean…?","TWN":"那麼那15天…？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"범이 마왕으로 거듭나기까지 남은 시간일세.","JPN":"虎が魔王になるまでの残り時間だ。","ENG":"That's the time left until the Tiger becomes a Demon Lord.","TWN":"是老虎蛻變為魔王，剩下的時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"세상이 마왕의 일부가 되고, 마왕이 세상의 일부가 되어… 설령 기적이 일어나 마왕을 처단해도, 그 순간 세상은 종말을 맞게 되겠지.","JPN":"世界が魔王の一部となり、魔王は世界の一部となり……たとえ奇跡が起きて魔王を倒すことができても、その瞬間世界は終末を迎えるだろう。","ENG":"Once that happens, the world becomes a part of the Demon Lord's as it becomes part of the world. And even if a miracle occurs and we manage to kill it, the world would end the moment we do.","TWN":"世界成為魔王的一部分，魔王成為世界的一部分… 就算發生奇蹟將魔王斬殺，那瞬間世界也會迎來末日。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"앞서 말했다시피, 우린 그걸 막기 위한 대책을 오랫동안 준비해왔다네.","JPN":"さっきも言ったように、我々は長い間、それを阻止するための対策を講じてきたんだ。","ENG":"That's why we've been preparing all this time to stop it.","TWN":"就像我之前說的，我們為了阻止那件事，準備了很長時間的應對措施。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 대책엔 자네의 도움이 반드시 필요한 동시에…","JPN":"そしてその対策を実行するためには、君の助けが必要で……","ENG":"And for that, we need your help…","TWN":"而那個應對措施，必須要有你的幫助…"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…걱정마시오.","JPN":"……心配はいらん。","ENG":"…No need to worry.","TWN":"…別擔心。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"작전의 개요와 그 <color=#ffd34c>위험성</color>에 대해선 이미 충분히 이해했으니.","JPN":"作戦の概要とその<color=#ffd34c>危険性</color>については、十分理解した。","ENG":"I understand exactly what's at stake and what kind of <color=#ffd34c>danger</color> this mission carries.","TWN":"關於作戰的概要和<color=#ffd34c>危險性</color>，我已經完全理解了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"작전 준비가 끝나면 다시 호출하겠네.","JPN":"作戦準備が終わったらまた呼ぼう。","ENG":"We'll call you when everything's ready.","TWN":"等作戰準備就緒，我會再次呼叫你。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"숙소로 안내해줄 테니, 잠시 눈이라도 붙이고 있게나.","JPN":"宿に案内する。しばらく仮眠でもとってくれ。","ENG":"In the meantime, get some rest. I'll have someone show you to your quarters.","TWN":"我會帶你去宿舍，你先休息一下。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"여전히 처음부터 끝까지 글귀라곤 하나도 보이지 않는군.","JPN":"相変わらず最初から最後まで、文字の一つも見当たらんな。","ENG":"Still nothing. Not a single letter left in this book.","TWN":"那本書依然從頭到尾都看不到任何文字。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"멀쩡했던 글귀가 사라질 이유라면, 그것은 분명 정보 오염의 영향일 터…","JPN":"確かにあった文字が消えたとすれば、それは情報汚染の影響のはず………","ENG":"If the text disappeared, it must've been due to the data corruption…","TWN":"本來好好的文字會消失，那肯定是資訊污染的影響…"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"명달 대장이 그 점을 간과했을 리는 없다.","JPN":"アカタツ隊長がそれを見落としていたとは思えない。","ENG":"No way Commander Myeongdal would've overlooked that.","TWN":"明達隊長不可能忽略這一點。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"천재란 녀석이 하나부터 열까지 설명해줘야 알겠더냐?","JPN":"天才ともあろうものが、いちいち説明しないと分からないのか？","ENG":"You need someone to spell it all out for you, genius?","TWN":"你這傢伙是天才，難道每件事都要我從頭到尾解釋給你聽嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"늘 하던 대로, 피땀 흘려 재주껏 알아내야지.","JPN":"いつも通り、血と汗を流し、使えるものはすべて使って見つけ出せ。","ENG":"Figure it out like you always do. Bleed, sweat, and earn it.","TWN":"像以前一樣，靠著血汗和你的本事自己找出來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"늘 하던 대로… 재주껏…","JPN":"いつも通り……","ENG":"Like you always do… Earn it…","TWN":"像以前一樣… 靠著本事…"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"피와 땀을 흘려…","JPN":"血と汗を長し……","ENG":"Bleed, sweat…","TWN":"流著血和汗…"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"저기, 서생 씨.","JPN":"あの、ショウさん。","ENG":"Um, Seosaeng?","TWN":"那個，書生。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"필요없다곤 하셨지만 그래도 배는 채우셔야 할 것 같아서요.","JPN":"必要ないと仰いましたが、やっぱり食事はしたほうがいいかと思って。","ENG":"You said you didn't need anything, but I figured you should at least eat something.","TWN":"你說不需要，但你還是得填飽肚子。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"식당에서 요깃거리 좀 가져왔…","JPN":"食堂から軽く食べられるものを持ってき……","ENG":"So I brought a little something for you…","TWN":"我從餐廳帶了些點心來…"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"으악! 뭐하는 겁니까!","JPN":"うわあっ！　何をしているんですか！","ENG":"Whoa! What are you doing?!","TWN":"啊！你在幹什麼！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"멈추세요! 대체 관리자님이 얼마나 부담을 줬길래 칼로 자해까지 하는 겁니까!","JPN":"やめてください！　プレッシャーを感じるからといって、自分を傷つけるのはよくありません！","ENG":"Please stop! Just how much pressure did the Administrator put on you, for you to go as far as hurting yourself with a knife?!","TWN":"請不要這樣！管理者到底給了你多大的壓力，讓你用刀自殘！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"놀라게 했다면 미안하군.","JPN":"すまない、驚かせてしまったか。","ENG":"Apologies. I didn't mean to alarm you.","TWN":"嚇到你了，很抱歉。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"그야 눈앞에서 사람이 피를 흘리고 있으면 당연히 놀라죠! 우리 그 칼부터 내려놓고 얘기해요! 네?","JPN":"人が自害しているところを目撃したら驚きますよ！　とりあえずそのナイフは下ろしてから話しましょう！","ENG":"Well, I did! Anyone would if they saw someone bleeding! Put the knife down and talk to me, okay?","TWN":"當著我的面流血，當然會被嚇到！我們先放下那把刀，好好談談吧！好嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"오해일세. 난 수수께끼를 풀고 있던 것 뿐이니까.","JPN":"落ち着きたまえ。某は自害ではなく、謎解きをしていただけだ。","ENG":"Calm down. I was just solving a riddle.","TWN":"是個誤會。我只是在解一個謎題。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"피를 흘려서 수수께끼를 푼다고요? 그게 무슨 뚱딴지 같은…","JPN":"血を流して謎解き？　それはどういう……","ENG":"You're solving a riddle by bleeding? What kind of nonsense is–","TWN":"流著血解謎題？這什麼奇奇怪怪的…"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"…이게 뭐죠?","JPN":"……これは何ですか？","ENG":"…What's that?","TWN":"…這是什麼？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L12_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"방금까지 아무것도 없던 페이지가 피에 젖으면서… 웬 글귀가 보이기 시작했어요.","JPN":"何も書かれてなかった紙が血に濡れて、文字が浮かび上がったような。","ENG":"The page was completely blank just a moment ago… but now, as it's soaked in blood, some kind of writing is starting to appear.","TWN":"剛才還什麼都沒有的頁面，沾到血之後… 竟然出現了文字。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내 눈에도 그리 보인다네.","JPN":"某にもそう見えている。","ENG":"I see it, too.","TWN":"我也看到了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"호랑이는 곶감을 무서워한다…? 이게 무슨 뜻이죠?","JPN":"虎は干し柿を恐れる……？　どういう意味ですか？","ENG":"The Tiger fears dried persimmons…? What's that supposed to mean?","TWN":"老虎害怕柿餅…？這是什麼意思？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"앗, 멋대로 봐서 죄송해요. 비밀 문서 같은 거죠?","JPN":"あっ、勝手に見てすみません。秘密文書のようなものですよね。","ENG":"Ah, sorry! I shouldn't have looked. Is it some kind of secret document?","TWN":"啊，很抱歉我隨便看了。這是機密文件吧？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"금방 잊어버리겠습니다! 저 까먹는 건 자신있어요!","JPN":"すぐ忘れます！　ボク忘れることなら自信あります！","ENG":"Don't worry, I'll forget it! I'm great at forgetting stuff!","TWN":"我馬上忘掉！我很擅長忘記的！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그럴 필요 없네.","JPN":"……その必要はない。","ENG":"…No need.","TWN":"…不用了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"실은 나도 이 글귀가 무슨 의미인지 전혀 모르겠거든.","JPN":"実は某もまったく意味が分からないのでな。","ENG":"I haven't the faintest idea what it means either.","TWN":"其實我也不知道這些文字是什麼意思。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 옥수수는 내 건가?","JPN":"そのトウモロコシ、某の分か？","ENG":"That corn. Is it for me?","TWN":"那個玉米。是給我的嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"아, 네! 혹시 옥수수는 싫어하시나요?","JPN":"あ、はい！　もしかして苦手ですか？","ENG":"Oh! Yes! Unless you don't like corn?","TWN":"啊，對！你不喜歡玉米嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그럴 리가. 고맙게 먹지.","JPN":"いや、ありがたくいただこう。","ENG":"Of course not. Thank you.","TWN":"怎麼會。我會好好享用。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"<color=#ffd34c>호랑이는 곶감을 무서워한다</color>라…","JPN":"<color=#ffd34c>虎は干し柿を恐れる</color>か……","ENG":"<color=#ffd34c>The Tiger fears dried persimmons</color>…","TWN":"<color=#ffd34c>老虎害怕柿餅</color>…"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"명달 대장, 본인이 아무리 천재라곤 하지만…","JPN":"アカタツ隊長、いくら某が天才とはいえ……","ENG":"Commander Myeongdal, I, for sure, am a genius…","TWN":"明達隊長，就算你再怎麼天才…"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 수수께끼는 좀 어렵구려.","JPN":"この謎は、少々骨が折れそうなのだが。","ENG":"But even to me, this riddle is rather obscure.","TWN":"這個謎題也太難了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"준비는 끝났다.","JPN":"準備は終わった。","ENG":"Everything's ready.","TWN":"準備結束了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"지시만 하면 우리가 범이 있는 영역까지 길을 열도록 하지.","JPN":"指示さえしてくれれば、私たちが虎の領域まで道を開く。","ENG":"Just give the word and we'll open a path to where the Tiger is.","TWN":"只要你發出指示，我們就會為你打開通往老虎領域的道路。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"범의 영역은 클리파 차원이라 불리는 오염된 공간일세.","JPN":"虎の領域は、クリファ次元と呼ばれる汚染された空間だ。","ENG":"The Tiger's domain is a place we call the Qlipha Dimension.","TWN":"老虎的領域被稱為逆卡巴拉次元，是個被污染的空間。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 대원이 길을 여는 순간, 유출된 클리파 에너지가 현실을 침식해나가겠지.","JPN":"うちの隊員が道を開いた瞬間、流れ出たクリファエネルギーが現実を侵食していくだろう。","ENG":"The moment our team breaches it, the Qlipha energy will begin leaking into the Normalside.","TWN":"我們的隊員打開道路的瞬間，洩漏出來的逆卡巴拉能量會侵蝕現實。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"한 번 시작되면 돌이킬 수 없게 되겠구려.","JPN":"一度始まると取り返しがつかぬということか。","ENG":"And once it starts, there's no going back.","TWN":"一旦開始，就無法回頭了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"각오는 되었나?","JPN":"覚悟はいいかね？","ENG":"Are you prepared?","TWN":"你做好覺悟了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"본인의 역할은 전부 이해했소.","JPN":"某の役目については理解した。","ENG":"I understand everything I need to do.","TWN":"我已經完全理解自己的角色了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그것을 위해 치러야 할 대가가 무엇인지도.","JPN":"そのために払うべき代償が何かについても。","ENG":"And what price I'll have to pay.","TWN":"以及為此要付出的代價。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 이것을 받아두게.","JPN":"ならば、これを受け取りたまえ。","ENG":"Then take this.","TWN":"那麼請收下這個。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이건… 환 같은 건가?","JPN":"これは……丸薬か？","ENG":"Is this… some kind of pill?","TWN":"這是… 幻覺藥嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정신살이라는 약일세. 일회용 각성제라고 생각하게나.","JPN":"精神丸という薬でな。使い捨ての覚醒剤だと思ってくれ。","ENG":"It is called Deathward. Think of it as a one-time-use stimulant.","TWN":"這是名為續命術的藥。把它當成一次性的覺醒劑吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"죽음을 피할 수 없는 상황을 직면한다면… 이게 목숨을 연명하는 데 도움이 될 걸세.","JPN":"どうしても死を免れない時に、延命に役立つだろう。","ENG":"If you ever find yourself facing inevitable death… this might help you stay alive.","TWN":"如果你面臨無法避免的死亡，這將有助於你延續生命。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"최선을 다해보리다.","JPN":"最善を尽くしてみよう。","ENG":"I'll give it everything I have.","TWN":"我會盡力而為。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};